protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // 1. Preserve old discriminator property name (EF9 changed default from "Discriminator" to "$type")
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

    // 2. Preserve old compound id format "Blog|1" (EF9 changed to key-only ids)
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);

    // 3. HasIndex removed — Cosmos DB throws at startup in EF9.
    //    Manage indexing via the Azure Portal or Bicep indexing policy instead.
}

